{
    final int mask = (1 << typeIndex);
    _hasNonDefaultCreator = true;
    AnnotatedWithParams oldOne = _creators[typeIndex];
    // already had an explicitly marked one?
    if (oldOne != null) {
        if ((_explicitCreators & mask) != 0) {
            // already had explicitly marked, leave as-is
            return;
        }
    }
    // indicate explicitly
    if (explicit) {
        _explicitCreators |= mask;
    }

    // check for conflicts
    if (oldOne != null && oldOne.getClass() == newOne.getClass()) {
        // [databind#667]: avoid one particular class of bogus problems
        if (getClass().getSimpleName().equals(oldOne.getClass().getSimpleName())) {
            throw new IllegalArgumentException("Conflicting incompatible creators:" +
                    " already had explicitly marked " + oldOne + ", encountered " + newOne);
        }
    }

    // update
    _creators[typeIndex] = _fixAccess(newOne);
}

